## Implementing Custom Platform Services

While OpenMaui provides comprehensive platform services out of the box, there are scenarios where you might need to implement custom services or extend existing ones. This section provides practical guidance for creating your own platform services.

## Creating a Custom Service Interface

First, define a cross-platform interface in your shared MAUI project:

```csharp
public interface ICustomPlatformService
{
    Task<string> GetSystemInformationAsync();
    Task<bool> PerformPlatformSpecificOperationAsync(string parameter);
    event EventHandler<PlatformEventArgs> PlatformEventOccurred;
}

public class PlatformEventArgs : EventArgs
{
    public string EventType { get; set; }
    public object Data { get; set; }
}
```

## Implementing the Linux-Specific Service

Create a Linux-specific implementation in your platform project:

```csharp
public class LinuxCustomPlatformService : ICustomPlatformService
{
    private readonly ILogger<LinuxCustomPlatformService> _logger;
    private DBusConnection _dbusConnection;

    public event EventHandler<PlatformEventArgs> PlatformEventOccurred;

    public LinuxCustomPlatformService(ILogger<LinuxCustomPlatformService> logger)
    {
        _logger = logger;
        InitializeDBusMonitoring();
    }

    public async Task<string> GetSystemInformationAsync()
    {
        try
        {
            // Query system information via D-Bus
            var connection = await DBusConnection.ConnectSystemBusAsync();

            var result = await connection.CallMethodAsync(
                "org.freedesktop.hostname1",
                "/org/freedesktop/hostname1",
                "org.freedesktop.DBus.Properties",
                "GetAll",
                new object[] { "org.freedesktop.hostname1" }
            );

            return ProcessSystemInfo(result);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to get system information");
            return "Unknown";
        }
    }

    public async Task<bool> PerformPlatformSpecificOperationAsync(string parameter)
    {
        // Example: Execute a command-line operation
        var process = new Process
        {
            StartInfo = new ProcessStartInfo
            {
                FileName = "/bin/bash",
                Arguments = $"-c \"{parameter}\"",
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                UseShellExecute = false
            }
        };

        process.Start();
        await process.WaitForExitAsync();

        return process.ExitCode == 0;
    }

    private void InitializeDBusMonitoring()
    {
        Task.Run(async () =>
        {
            _dbusConnection = await DBusConnection.ConnectSessionBusAsync();

            await _dbusConnection.AddMatchAsync(
                "type='signal',interface='org.custom.Interface'"
            );

            _dbusConnection.OnSignal += (sender, args) =>
            {
                PlatformEventOccurred?.Invoke(this, new PlatformEventArgs
                {
                    EventType = args.Member,
                    Data = args.Parameters
                });
            };
        });
    }
}
```

## Registering the Custom Service

Register your service during application configuration:

```csharp
public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureLinuxPlatform();

#if LINUX
        // Register custom Linux service
        builder.Services.AddSingleton<ICustomPlatformService, LinuxCustomPlatformService>();
#elif WINDOWS
        builder.Services.AddSingleton<ICustomPlatformService, WindowsCustomPlatformService>();
#elif ANDROID || IOS
        builder.Services.AddSingleton<ICustomPlatformService, MobileCustomPlatformService>();
#endif

        return builder.Build();
    }
}
```

## Using Dependency Injection

Consume your custom service through dependency injection:

```csharp
public class MainViewModel : INotifyPropertyChanged
{
    private readonly ICustomPlatformService _platformService;
    private string _systemInfo;

    public MainViewModel(ICustomPlatformService platformService)
    {
        _platformService = platformService;
        _platformService.PlatformEventOccurred += OnPlatformEvent;

        LoadSystemInfoCommand = new Command(async () => await LoadSystemInfo());
    }

    public string SystemInfo
    {
        get => _systemInfo;
        set
        {
            _systemInfo = value;
            OnPropertyChanged();
        }
    }

    public ICommand LoadSystemInfoCommand { get; }

    private async Task LoadSystemInfo()
    {
        SystemInfo = await _platformService.GetSystemInformationAsync();
    }

    private void OnPlatformEvent(object sender, PlatformEventArgs e)
    {
        // Handle platform-specific events
        Debug.WriteLine($"Platform event: {e.EventType}");
    }
}
```

## Best Practices for Custom Services

### 1. Error Handling and Fallbacks

Always provide graceful fallbacks when platform features aren't available:

```csharp
public async Task<bool> TryPlatformFeatureAsync()
{
    try
    {
        // Try primary implementation
        return await PrimaryImplementation();
    }
    catch (PlatformNotSupportedException)
    {
        // Try fallback
        return await FallbackImplementation();
    }
    catch (Exception ex)
    {
        _logger.LogWarning(ex, "Platform feature unavailable");
        return false;
    }
}
```

### 2. Asynchronous Operations

Use async/await for operations that might block:

```csharp
public async Task<T> CallNativeServiceAsync<T>()
{
    return await Task.Run(() =>
    {
        // Long-running native operation
        return NativeInterop.PerformOperation();
    });
}
```

### 3. Resource Cleanup

Implement IDisposable for services that manage native resources:

```csharp
public class LinuxCustomService : ICustomPlatformService, IDisposable
{
    private DBusConnection _connection;
    private bool _disposed;

    public void Dispose()
    {
        Dispose(true);
        GC.SuppressFinalize(this);
    }

    protected virtual void Dispose(bool disposing)
    {
        if (!_disposed)
        {
            if (disposing)
            {
                _connection?.Dispose();
            }
            _disposed = true;
        }
    }
}
```

### 4. Thread Safety

Ensure thread-safe access to shared resources:

```csharp
private readonly SemaphoreSlim _semaphore = new SemaphoreSlim(1, 1);

public async Task<string> ThreadSafeOperationAsync()
{
    await _semaphore.WaitAsync();
    try
    {
        return await PerformOperation();
    }
    finally
    {
        _semaphore.Release();
    }
}
```

## Testing Custom Services

Create testable services by using interfaces and dependency injection:

```csharp
public class CustomServiceTests
{
    [Fact]
    public async Task GetSystemInformation_ReturnsValidData()
    {
        // Arrange
        var mockLogger = new Mock<ILogger<LinuxCustomPlatformService>>();
        var service = new LinuxCustomPlatformService(mockLogger.Object);

        // Act
        var result = await service.GetSystemInformationAsync();

        // Assert
        Assert.NotNull(result);
        Assert.NotEmpty(result);
    }

    [Fact]
    public async Task PlatformOperation_WithInvalidParameter_ReturnsFalse()
    {
        // Arrange
        var service = new LinuxCustomPlatformService(Mock.Of<ILogger<LinuxCustomPlatformService>>());

        // Act
        var result = await service.PerformPlatformSpecificOperationAsync("invalid");

        // Assert
        Assert.False(result);
    }
}
```

By following these patterns and best practices, you can extend OpenMaui's platform services to meet your application's specific needs while maintaining code quality, testability, and cross-platform compatibility. The key is to leverage the existing infrastructure—dependency injection, async patterns, and error handling—that OpenMaui provides as a foundation.

---

> The platform services layer achieves 100% MAUI API compliance, allowing existing MAUI applications to run on Linux with minimal or no code changes.

> By leveraging xdg-desktop-portal with fallbacks to zenity and kdialog, OpenMaui ensures file picker functionality works seamlessly across GNOME, KDE, and other desktop environments.

> Desktop notifications via D-Bus provide a native, standards-compliant way to alert users without depending on specific desktop environment implementations.

sections.content:
The platform services architecture in OpenMaui follows a layered approach that prioritizes standards-based implementations while providing robust fallbacks for maximum compatibility.

## The Service Layer Pattern

Each platform service in OpenMaui implements the corresponding MAUI interface, ensuring seamless integration with the MAUI framework. The services are registered during application bootstrapping through the `MauiAppBuilder` extension methods:

```csharp
public static MauiAppBuilder ConfigureLinuxPlatform(this MauiAppBuilder builder)
{
    builder.Services.AddSingleton<IFilePicker, LinuxFilePicker>();
    builder.Services.AddSingleton<IClipboard, LinuxClipboard>();
    builder.Services.AddSingleton<ISecureStorage, LinuxSecureStorage>();
    builder.Services.AddSingleton<IPreferences, LinuxPreferences>();
    builder.Services.AddSingleton<ILauncher, LinuxLauncher>();
    builder.Services.AddSingleton<IShare, LinuxShare>();
    // ... additional services
    return builder;
}
```

This dependency injection approach allows for easy testing, mocking, and service replacement when needed.

## Desktop Environment Detection

A critical component of the platform services architecture is the ability to detect and adapt to different desktop environments. OpenMaui uses environment variables and D-Bus introspection to determine the current desktop:

```csharp
public static DesktopEnvironment DetectDesktopEnvironment()
{
    var xdgCurrentDesktop = Environment.GetEnvironmentVariable("XDG_CURRENT_DESKTOP");
    var desktopSession = Environment.GetEnvironmentVariable("DESKTOP_SESSION");

    if (xdgCurrentDesktop?.Contains("GNOME") == true)
        return DesktopEnvironment.Gnome;
    if (xdgCurrentDesktop?.Contains("KDE") == true)
        return DesktopEnvironment.Kde;
    if (xdgCurrentDesktop?.Contains("XFCE") == true)
        return DesktopEnvironment.Xfce;

    return DesktopEnvironment.Unknown;
}
```

This detection mechanism enables OpenMaui to select the most appropriate native implementation for each service, ensuring a native look and feel regardless of the desktop environment.

## Standards-First Approach

Wherever possible, OpenMaui prioritizes **freedesktop.org standards** like xdg-desktop-portal and D-Bus specifications. These standards provide consistent APIs across desktop environments and are actively maintained by the Linux desktop community. When standards-based implementations aren't available, OpenMaui gracefully falls back to desktop-specific tools or custom implementations.

File and folder pickers are essential platform services that allow users to browse and select files from their system. On Linux, implementing these pickers requires navigating a complex landscape of desktop-specific dialogs and standards-based portals.

## The xdg-desktop-portal Standard

The modern, standards-based approach to file pickers on Linux is **xdg-desktop-portal**, a D-Bus service that provides a desktop-agnostic API for file chooser dialogs. OpenMaui's `LinuxFilePicker` service attempts to use this portal first:

```csharp
public async Task<FileResult> PickAsync(PickOptions options = null)
{
    try
    {
        // Try xdg-desktop-portal first (modern standard)
        if (await IsXdgPortalAvailable())
        {
            return await PickViaXdgPortal(options);
        }
    }
    catch (Exception ex)
    {
        // Log and fall back to alternative methods
    }

    // Fallback to desktop-specific implementations
    var desktopEnv = DetectDesktopEnvironment();
    return desktopEnv switch
    {
        DesktopEnvironment.Kde => await PickViaKDialog(options),
        DesktopEnvironment.Gnome => await PickViaZenity(options),
        _ => await PickViaZenity(options) // Zenity as universal fallback
    };
}
```

The xdg-desktop-portal approach offers several advantages:
- **Sandboxing support**: Works seamlessly with Flatpak and Snap applications
- **Consistent behavior**: Same API across all desktop environments
- **Security**: Proper permission handling for file access

## Zenity: The Universal Fallback

**Zenity** is a command-line tool that displays GTK+ dialogs from shell scripts. It's widely available across Linux distributions and provides a reliable fallback when xdg-desktop-portal isn't available:

```csharp
private async Task<FileResult> PickViaZenity(PickOptions options)
{
    var args = new List<string> { "--file-selection" };

    if (options?.PickerTitle != null)
        args.Add($"--title={options.PickerTitle}");

    // Add file type filters
    if (options?.FileTypes?.Value != null)
    {
        foreach (var fileType in options.FileTypes.Value)
        {
            args.Add($"--file-filter={fileType}|{fileType}");
        }
    }

    var process = Process.Start(new ProcessStartInfo
    {
        FileName = "zenity",
        Arguments = string.Join(" ", args),
        RedirectStandardOutput = true,
        UseShellExecute = false
    });

    var output = await process.StandardOutput.ReadToEndAsync();
    await process.WaitForExitAsync();

    if (process.ExitCode == 0 && !string.IsNullOrWhiteSpace(output))
    {
        var filePath = output.Trim();
        return new FileResult(filePath);
    }

    return null; // User cancelled
}
```

Zenity's simplicity makes it an excellent fallback—it requires no complex D-Bus communication and works reliably across most Linux distributions.

## KDialog for KDE Integration

For KDE Plasma users, **kdialog** provides a native Qt-based file picker that matches the desktop's visual style:

```csharp
private async Task<FileResult> PickViaKDialog(PickOptions options)
{
    var args = new List<string> { "--getopenfilename", ".", "*.*" };

    if (options?.PickerTitle != null)
        args.Add($"--title={options.PickerTitle}");

    var process = Process.Start(new ProcessStartInfo
    {
        FileName = "kdialog",
        Arguments = string.Join(" ", args),
        RedirectStandardOutput = true,
        UseShellExecute = false
    });

    var output = await process.StandardOutput.ReadToEndAsync();
    await process.WaitForExitAsync();

    if (process.ExitCode == 0 && !string.IsNullOrWhiteSpace(output))
    {
        return new FileResult(output.Trim());
    }

    return null;
}
```

## Folder Pickers and Multiple Selection

OpenMaui's file picker implementation also supports folder selection and multiple file selection through the same fallback chain:

```csharp
public async Task<FolderResult> PickFolderAsync()
{
    if (await IsXdgPortalAvailable())
    {
        return await PickFolderViaXdgPortal();
    }

    // Zenity folder selection
    var process = Process.Start(new ProcessStartInfo
    {
        FileName = "zenity",
        Arguments = "--file-selection --directory",
        RedirectStandardOutput = true,
        UseShellExecute = false
    });

    var output = await process.StandardOutput.ReadToEndAsync();
    await process.WaitForExitAsync();

    if (process.ExitCode == 0 && !string.IsNullOrWhiteSpace(output))
    {
        return new FolderResult(output.Trim());
    }

    return null;
}
```

By leveraging xdg-desktop-portal with fallbacks to zenity and kdialog, OpenMaui ensures file picker functionality works seamlessly across GNOME, KDE, and other desktop environments while maintaining the familiar MAUI API surface.

Storing sensitive data like authentication tokens, API keys, and user credentials requires a secure, encrypted storage mechanism. On Linux, the standard solution is **libsecret**, a library that provides access to the Secret Service API—a freedesktop.org specification implemented by GNOME Keyring, KWallet, and other password managers.

## The Secret Service API

The Secret Service API uses D-Bus to communicate with the system's password manager. OpenMaui's `LinuxSecureStorage` service implements the MAUI `ISecureStorage` interface using libsecret:

```csharp
public class LinuxSecureStorage : ISecureStorage
{
    private const string SchemaName = "com.openmaui.securestorage";

    public async Task SetAsync(string key, string value)
    {
        if (string.IsNullOrEmpty(key))
            throw new ArgumentNullException(nameof(key));

        try
        {
            await StoreSecretAsync(key, value);
        }
        catch (Exception ex)
        {
            throw new SecureStorageException($"Failed to store secret: {ex.Message}", ex);
        }
    }

    public async Task<string> GetAsync(string key)
    {
        if (string.IsNullOrEmpty(key))
            throw new ArgumentNullException(nameof(key));

        try
        {
            return await RetrieveSecretAsync(key);
        }
        catch (Exception ex)
        {
            throw new SecureStorageException($"Failed to retrieve secret: {ex.Message}", ex);
        }
    }

    public bool Remove(string key)
    {
        if (string.IsNullOrEmpty(key))
            throw new ArgumentNullException(nameof(key));

        try
        {
            return DeleteSecret(key);
        }
        catch
        {
            return false;
        }
    }

    public void RemoveAll()
    {
        try
        {
            ClearAllSecrets();
        }
        catch (Exception ex)
        {
            throw new SecureStorageException($"Failed to clear secrets: {ex.Message}", ex);
        }
    }
}
```

## P/Invoke Integration with libsecret

Under the hood, OpenMaui uses P/Invoke to call libsecret's native functions:

```csharp
internal static class LibSecretInterop
{
    [DllImport("libsecret-1.so.0")]
    internal static extern IntPtr secret_password_store_sync(
        IntPtr schema,
        string collection,
        string label,
        string password,
        IntPtr cancellable,
        out IntPtr error,
        IntPtr end);

    [DllImport("libsecret-1.so.0")]
    internal static extern IntPtr secret_password_lookup_sync(
        IntPtr schema,
        IntPtr cancellable,
        out IntPtr error,
        IntPtr end);

    [DllImport("libsecret-1.so.0")]
    internal static extern bool secret_password_clear_sync(
        IntPtr schema,
        IntPtr cancellable,
        out IntPtr error,
        IntPtr end);

    [DllImport("libsecret-1.so.0")]
    internal static extern IntPtr secret_schema_new(
        string name,
        int flags,
        IntPtr end);
}
```

## Schema Definition and Attributes

Secure storage items in libsecret are organized using schemas. OpenMaui defines a custom schema for MAUI applications:

```csharp
private IntPtr CreateSchema()
{
    // Create a schema with attributes for organizing secrets
    var schema = LibSecretInterop.secret_schema_new(
        SchemaName,
        (int)SecretSchemaFlags.NONE,
        IntPtr.Zero
    );

    return schema;
}

private async Task StoreSecretAsync(string key, string value)
{
    var schema = CreateSchema();
    var label = $"OpenMaui Secure Storage: {key}";

    IntPtr error;
    var result = LibSecretInterop.secret_password_store_sync(
        schema,
        "default", // Collection name
        label,
        value,
        IntPtr.Zero, // Cancellable
        out error,
        IntPtr.Zero // Attribute terminator
    );

    if (error != IntPtr.Zero)
    {
        var errorMessage = Marshal.PtrToStringAnsi(error);
        throw new SecureStorageException($"Failed to store secret: {errorMessage}");
    }
}
```

## Encryption and Security Considerations

libsecret provides several important security guarantees:

1. **Encryption at rest**: Secrets are encrypted using the user's login credentials
2. **Process isolation**: Only authorized processes can access stored secrets
3. **Desktop integration**: Seamless integration with GNOME Keyring, KWallet, and other password managers
4. **Automatic unlocking**: Secrets are automatically unlocked when the user logs in

## Fallback for Headless Environments

For servers or headless environments where libsecret isn't available, OpenMaui provides a fallback implementation using encrypted file storage:

```csharp
private bool IsLibSecretAvailable()
{
    try
    {
        // Try to load libsecret
        var schema = CreateSchema();
        return schema != IntPtr.Zero;
    }
    catch
    {
        return false;
    }
}

private string GetFallbackStoragePath()
{
    var dataDir = Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData);
    return Path.Combine(dataDir, "openmaui", "securestorage");
}
```

This dual approach ensures that secure storage works reliably across different Linux configurations, from full desktop environments to containerized deployments.

Desktop notifications are a crucial part of modern application UX, allowing apps to alert users about important events even when the application isn't in focus. On Linux, desktop notifications are standardized through the **freedesktop.org Desktop Notifications Specification**, which uses D-Bus as the communication protocol.

## The Notifications D-Bus Interface

The notification system exposes a well-defined D-Bus interface at `org.freedesktop.Notifications`. OpenMaui's notification service communicates with this interface to display native notifications:

```csharp
public class LinuxNotificationService
{
    private const string NotificationBusName = "org.freedesktop.Notifications";
    private const string NotificationObjectPath = "/org/freedesktop/Notifications";
    private const string NotificationInterface = "org.freedesktop.Notifications";

    public async Task ShowNotificationAsync(
        string title,
        string message,
        string icon = null,
        int timeout = -1)
    {
        try
        {
            var notificationId = await SendNotificationViaDBus(
                title,
                message,
                icon,
                timeout
            );
        }
        catch (Exception ex)
        {
            // Fallback to alternative notification methods
            await ShowFallbackNotification(title, message);
        }
    }
}
```

## Sending Notifications via D-Bus

The notification service uses the `Notify` method of the D-Bus interface, which accepts several parameters:

```csharp
private async Task<uint> SendNotificationViaDBus(
    string title,
    string message,
    string icon,
    int timeout)
{
    var connection = await DBusConnection.ConnectSessionBusAsync();

    var parameters = new object[]
    {
        "OpenMaui",           // Application name
        0u,                   // Replaces ID (0 for new notification)
        icon ?? "",          // Icon name or path
        title,                // Summary
        message,              // Body
        new string[0],        // Actions
        new Dictionary<string, object>(), // Hints
        timeout               // Timeout (-1 for default)
    };

    var result = await connection.CallMethodAsync(
        NotificationBusName,
        NotificationObjectPath,
        NotificationInterface,
        "Notify",
        parameters
    );

    return (uint)result;
}
```

## Notification Actions and Callbacks

The Desktop Notifications Specification supports interactive notifications with action buttons. OpenMaui exposes this functionality through the MAUI API:

```csharp
public async Task<NotificationAction> ShowNotificationWithActionsAsync(
    string title,
    string message,
    params NotificationAction[] actions)
{
    var actionKeys = actions.Select(a => a.Id).ToArray();
    var actionLabels = actions.Select(a => a.Title).ToArray();

    // Flatten actions array for D-Bus (key, label, key, label, ...)
    var actionArray = new List<string>();
    for (int i = 0; i < actions.Length; i++)
    {
        actionArray.Add(actionKeys[i]);
        actionArray.Add(actionLabels[i]);
    }

    var parameters = new object[]
    {
        "OpenMaui",
        0u,
        "",
        title,
        message,
        actionArray.ToArray(),
        new Dictionary<string, object>(),
        -1
    };

    var notificationId = await SendNotificationAsync(parameters);

    // Listen for action invoked signal
    var actionInvoked = await WaitForActionInvokedAsync(notificationId);
    return actions.FirstOrDefault(a => a.Id == actionInvoked);
}
```

## Handling Notification Signals

When users interact with notifications, the notification daemon sends D-Bus signals back to the application:

```csharp
private async Task<string> WaitForActionInvokedAsync(uint notificationId)
{
    var connection = await DBusConnection.ConnectSessionBusAsync();
    var tcs = new TaskCompletionSource<string>();

    // Subscribe to ActionInvoked signal
    await connection.AddMatchAsync(
        $"type='signal',interface='{NotificationInterface}',member='ActionInvoked'"
    );

    connection.OnSignal += (sender, args) =>
    {
        if (args.Member == "ActionInvoked")
        {
            var id = (uint)args.Parameters[0];
            var actionKey = (string)args.Parameters[1];

            if (id == notificationId)
            {
                tcs.TrySetResult(actionKey);
            }
        }
    };

    return await tcs.Task;
}
```

## Notification Hints and Capabilities

The Desktop Notifications Specification supports various hints to customize notification appearance and behavior:

```csharp
private Dictionary<string, object> CreateNotificationHints(
    NotificationPriority priority,
    string category,
    bool resident)
{
    var hints = new Dictionary<string, object>();

    // Urgency level (0=low, 1=normal, 2=critical)
    hints["urgency"] = priority switch
    {
        NotificationPriority.Low => (byte)0,
        NotificationPriority.High => (byte)2,
        _ => (byte)1
    };

    // Category for grouping notifications
    if (!string.IsNullOrEmpty(category))
        hints["category"] = category;

    // Resident notifications stay in notification center
    if (resident)
        hints["resident"] = true;

    // Desktop entry for proper app identification
    hints["desktop-entry"] = "com.openmaui.app";

    return hints;
}
```

## Querying Notification Capabilities

Different notification daemons support different features. OpenMaui queries capabilities to adapt behavior:

```csharp
public async Task<string[]> GetServerCapabilitiesAsync()
{
    var connection = await DBusConnection.ConnectSessionBusAsync();

    var result = await connection.CallMethodAsync(
        NotificationBusName,
        NotificationObjectPath,
        NotificationInterface,
        "GetCapabilities",
        Array.Empty<object>()
    );

    return (string[])result;
}

public async Task<bool> SupportsActionsAsync()
{
    var capabilities = await GetServerCapabilitiesAsync();
    return capabilities.Contains("actions");
}
```

Common capabilities include:
- `actions`: Support for action buttons
- `body`: Support for notification body text
- `body-markup`: Support for HTML markup in body
- `icon-static`: Support for static icons
- `persistence`: Notifications persist in notification center
- `sound`: Support for notification sounds

By using the standard D-Bus notification interface, OpenMaui ensures that notifications work consistently across all Linux desktop environments while respecting each desktop's visual style and user preferences.

Clipboard operations and content sharing are fundamental platform services that enable data exchange between applications. On Linux, these services require different approaches depending on the display server (X11 vs. Wayland) and desktop environment.

## Clipboard Architecture

Linux clipboard systems are more complex than other platforms, supporting multiple selection types:

1. **PRIMARY**: Text selected with the mouse (middle-click paste)
2. **CLIPBOARD**: Explicit copy/paste operations (Ctrl+C/Ctrl+V)
3. **SECONDARY**: Rarely used selection buffer

OpenMaui's `LinuxClipboard` service focuses on the CLIPBOARD selection, which matches user expectations from other platforms:

```csharp
public class LinuxClipboard : IClipboard
{
    private readonly IDisplayServer _displayServer;

    public LinuxClipboard(IDisplayServer displayServer)
    {
        _displayServer = displayServer;
    }

    public async Task SetTextAsync(string text)
    {
        if (_displayServer is X11DisplayServer x11)
        {
            await SetTextViaX11(x11, text);
        }
        else if (_displayServer is WaylandDisplayServer wayland)
        {
            await SetTextViaWayland(wayland, text);
        }
        else
        {
            // Fallback to xclip/xsel command-line tools
            await SetTextViaCommandLine(text);
        }
    }

    public async Task<string> GetTextAsync()
    {
        if (_displayServer is X11DisplayServer x11)
        {
            return await GetTextViaX11(x11);
        }
        else if (_displayServer is WaylandDisplayServer wayland)
        {
            return await GetTextViaWayland(wayland);
        }
        else
        {
            return await GetTextViaCommandLine();
        }
    }

    public bool HasText => !string.IsNullOrEmpty(GetTextAsync().Result);
}
```

## X11 Clipboard Implementation

On X11, clipboard operations use the X Selection mechanism with property notifications:

```csharp
private async Task SetTextViaX11(X11DisplayServer x11, string text)
{
    var display = x11.Display;
    var window = x11.RootWindow;

    // Get CLIPBOARD atom
    var clipboardAtom = X11Interop.XInternAtom(
        display,
        "CLIPBOARD",
        false
    );

    // Get UTF8_STRING atom for text encoding
    var utf8Atom = X11Interop.XInternAtom(
        display,
        "UTF8_STRING",
        false
    );

    // Set selection owner
    X11Interop.XSetSelectionOwner(
        display,
        clipboardAtom,
        window,
        X11Interop.CurrentTime
    );

    // Store text data
    _clipboardData = text;
    _clipboardEncoding = utf8Atom;

    // Handle selection requests from other applications
    x11.OnSelectionRequest += HandleSelectionRequest;
}

private void HandleSelectionRequest(object sender, X11SelectionRequestEvent e)
{
    if (e.Selection == _clipboardAtom && _clipboardData != null)
    {
        // Convert text to requested format
        var data = Encoding.UTF8.GetBytes(_clipboardData);

        // Send selection notify event
        X11Interop.XChangeProperty(
            e.Display,
            e.Requestor,
            e.Property,
            _clipboardEncoding,
            8, // 8-bit data
            PropMode.Replace,
            data,
            data.Length
        );

        X11Interop.XSendEvent(
            e.Display,
            e.Requestor,
            false,
            0,
            CreateSelectionNotifyEvent(e)
        );
    }
}
```

## Wayland Clipboard Implementation

Wayland uses a different approach with data device managers and offers:

```csharp
private async Task SetTextViaWayland(WaylandDisplayServer wayland, string text)
{
    var dataDeviceManager = wayland.DataDeviceManager;
    var seat = wayland.Seat;

    // Create data source
    var dataSource = dataDeviceManager.CreateDataSource();

    // Offer text/plain mime type
    dataSource.Offer("text/plain;charset=utf-8");
    dataSource.Offer("text/plain");
    dataSource.Offer("TEXT");
    dataSource.Offer("STRING");

    // Handle send requests
    dataSource.OnSend += (mimeType, fd) =>
    {
        var bytes = Encoding.UTF8.GetBytes(text);
        using var stream = new UnixStream(fd);
        stream.Write(bytes, 0, bytes.Length);
        stream.Flush();
    };

    // Set selection
    var dataDevice = dataDeviceManager.GetDataDevice(seat);
    dataDevice.SetSelection(dataSource, wayland.Serial);
}
```

## Command-Line Fallback

For maximum compatibility, OpenMaui provides a fallback using command-line tools:

```csharp
private async Task SetTextViaCommandLine(string text)
{
    // Try xclip first (most common)
    if (await IsCommandAvailable("xclip"))
    {
        await RunCommand("xclip", "-selection clipboard", text);
        return;
    }

    // Fall back to xsel
    if (await IsCommandAvailable("xsel"))
    {
        await RunCommand("xsel", "--clipboard --input", text);
        return;
    }

    throw new PlatformNotSupportedException(
        "No clipboard mechanism available. Install xclip or xsel."
    );
}

private async Task<string> GetTextViaCommandLine()
{
    if (await IsCommandAvailable("xclip"))
    {
        return await RunCommandOutput("xclip", "-selection clipboard -o");
    }

    if (await IsCommandAvailable("xsel"))
    {
        return await RunCommandOutput("xsel", "--clipboard --output");
    }

    return null;
}
```

## Share Functionality

The share service allows applications to share content with other applications. On Linux, this is typically implemented using xdg-open or desktop-specific sharing mechanisms:

```csharp
public class LinuxShare : IShare
{
    public async Task RequestAsync(ShareTextRequest request)
    {
        // Try desktop-specific share dialogs first
        if (await TryDesktopShare(request))
            return;

        // Fallback: copy to clipboard and notify user
        await Clipboard.SetTextAsync(request.Text);
        await ShowNotification(
            "Content Copied",
            "Content has been copied to clipboard"
        );
    }

    public async Task RequestAsync(ShareFileRequest request)
    {
        var filePath = request.File.FullPath;

        // Use xdg-open to open file with default handler
        var process = Process.Start(new ProcessStartInfo
        {
            FileName = "xdg-open",
            Arguments = $"\"{filePath}\"",
            UseShellExecute = false
        });

        await process.WaitForExitAsync();
    }

    private async Task<bool> TryDesktopShare(ShareTextRequest request)
    {
        var desktopEnv = DetectDesktopEnvironment();

        return desktopEnv switch
        {
            DesktopEnvironment.Gnome => await ShareViaGnome(request),
            DesktopEnvironment.Kde => await ShareViaKde(request),
            _ => false
        };
    }
}
```

The clipboard and share implementations demonstrate OpenMaui's commitment to working across different Linux configurations while providing a consistent API surface for MAUI developers.

Modern applications need to respect user theme preferences, particularly the increasingly popular dark mode. On Linux, theme detection requires querying desktop-specific settings and monitoring for changes.

## The SystemThemeService

OpenMaui's `SystemThemeService` provides a unified API for theme detection across different desktop environments:

```csharp
public class SystemThemeService
{
    private AppTheme _currentTheme;
    private readonly IDesktopEnvironmentDetector _desktopDetector;

    public event EventHandler<AppTheme> ThemeChanged;

    public SystemThemeService(IDesktopEnvironmentDetector desktopDetector)
    {
        _desktopDetector = desktopDetector;
        _currentTheme = DetectCurrentTheme();
        StartThemeMonitoring();
    }

    public AppTheme CurrentTheme => _currentTheme;

    private AppTheme DetectCurrentTheme()
    {
        var desktop = _desktopDetector.DetectDesktopEnvironment();

        return desktop switch
        {
            DesktopEnvironment.Gnome => DetectGnomeTheme(),
            DesktopEnvironment.Kde => DetectKdeTheme(),
            DesktopEnvironment.Xfce => DetectXfceTheme(),
            _ => DetectFallbackTheme()
        };
    }
}
```

## GNOME Theme Detection

GNOME stores theme preferences in GSettings (dconf), which can be queried via D-Bus or the gsettings command:

```csharp
private AppTheme DetectGnomeTheme()
{
    try
    {
        // Query via D-Bus for better performance
        var theme = QueryGSettingsViaDBus(
            "org.gnome.desktop.interface",
            "gtk-theme"
        );

        // Check color scheme preference (GNOME 42+)
        var colorScheme = QueryGSettingsViaDBus(
            "org.gnome.desktop.interface",
            "color-scheme"
        );

        if (colorScheme == "prefer-dark")
            return AppTheme.Dark;

        // Fallback: check if theme name contains "dark"
        if (theme?.Contains("dark", StringComparison.OrdinalIgnoreCase) == true)
            return AppTheme.Dark;

        return AppTheme.Light;
    }
    catch
    {
        return DetectFallbackTheme();
    }
}

private string QueryGSettingsViaDBus(string schema, string key)
{
    var connection = DBusConnection.ConnectSessionBus();

    var result = connection.CallMethod(
        "ca.desrt.dconf",
        "/ca/desrt/dconf/Writer/user",
        "ca.desrt.dconf.Writer",
        "Read",
        new object[] { $"/{schema.Replace('.', '/')}/{key}" }
    );

    return result?.ToString();
}
```

## KDE Plasma Theme Detection

KDE Plasma stores theme settings in configuration files that can be read directly:

```csharp
private AppTheme DetectKdeTheme()
{
    try
    {
        var configPath = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
            ".config",
            "kdeglobals"
        );

        if (!File.Exists(configPath))
            return AppTheme.Light;

        var config = File.ReadAllText(configPath);

        // Look for color scheme setting
        var colorSchemeMatch = Regex.Match(
            config,
            @"ColorScheme=(.+)$",
            RegexOptions.Multiline
        );

        if (colorSchemeMatch.Success)
        {
            var colorScheme = colorSchemeMatch.Groups[1].Value.Trim();
            if (colorScheme.Contains("Dark", StringComparison.OrdinalIgnoreCase))
                return AppTheme.Dark;
        }

        // Check LookAndFeelPackage for dark themes
        var lafMatch = Regex.Match(
            config,
            @"LookAndFeelPackage=(.+)$",
            RegexOptions.Multiline
        );

        if (lafMatch.Success)
        {
            var laf = lafMatch.Groups[1].Value.Trim();
            if (laf.Contains("dark", StringComparison.OrdinalIgnoreCase))
                return AppTheme.Dark;
        }

        return AppTheme.Light;
    }
    catch
    {
        return AppTheme.Light;
    }
}
```

## Theme Change Monitoring

To respond to theme changes in real-time, OpenMaui monitors the appropriate configuration sources:

```csharp
private void StartThemeMonitoring()
{
    var desktop = _desktopDetector.DetectDesktopEnvironment();

    switch (desktop)
    {
        case DesktopEnvironment.Gnome:
            MonitorGnomeThemeChanges();
            break;
        case DesktopEnvironment.Kde:
            MonitorKdeThemeChanges();
            break;
        default:
            MonitorFallbackThemeChanges();
            break;
    }
}

private void MonitorGnomeThemeChanges()
{
    // Subscribe to GSettings changes via D-Bus
    var connection = DBusConnection.ConnectSessionBus();

    connection.AddMatch(
        "type='signal',"
        + "interface='ca.desrt.dconf.Writer',"
        + "member='Notify'"
    );

    connection.OnSignal += (sender, args) =>
    {
        if (args.Path?.Contains("org/gnome/desktop/interface") == true)
        {
            var newTheme = DetectGnomeTheme();
            if (newTheme != _currentTheme)
            {
                _currentTheme = newTheme;
                ThemeChanged?.Invoke(this, newTheme);
            }
        }
    };
}

private void MonitorKdeThemeChanges()
{
    var configPath = Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
        ".config",
        "kdeglobals"
    );

    // Use FileSystemWatcher to monitor config file changes
    var watcher = new FileSystemWatcher
    {
        Path = Path.GetDirectoryName(configPath),
        Filter = Path.GetFileName(configPath),
        NotifyFilter = NotifyFilters.LastWrite
    };

    watcher.Changed += (sender, e) =>
    {
        var newTheme = DetectKdeTheme();
        if (newTheme != _currentTheme)
        {
            _currentTheme = newTheme;
            ThemeChanged?.Invoke(this, newTheme);
        }
    };

    watcher.EnableRaisingEvents = true;
}
```

## Applying Theme to MAUI Application

When a theme change is detected, OpenMaui updates the MAUI application's theme:

```csharp
public class LinuxApplication : IPlatformApplication
{
    private readonly SystemThemeService _themeService;

    public LinuxApplication(SystemThemeService themeService)
    {
        _themeService = themeService;
        _themeService.ThemeChanged += OnSystemThemeChanged;

        // Apply initial theme
        ApplyTheme(_themeService.CurrentTheme);
    }

    private void OnSystemThemeChanged(object sender, AppTheme newTheme)
    {
        ApplyTheme(newTheme);
    }

    private void ApplyTheme(AppTheme theme)
    {
        // Update MAUI application theme
        if (Application.Current != null)
        {
            Application.Current.UserAppTheme = theme;
        }

        // Update SkiaTheme for rendering
        SkiaTheme.Current.IsDarkMode = (theme == AppTheme.Dark);

        // Trigger redraw of all views
        foreach (var window in Windows)
        {
            window.InvalidateLayout();
        }
    }
}
```

## GTK Theme Integration

For native dialogs and GTK-based components, OpenMaui applies GTK CSS themes:

```csharp
public class GtkThemeService
{
    private GtkCssProvider _cssProvider;

    public void ApplyTheme(AppTheme theme)
    {
        if (_cssProvider != null)
        {
            Gtk.StyleContext.RemoveProviderForScreen(
                Gdk.Screen.Default,
                _cssProvider
            );
        }

        _cssProvider = new GtkCssProvider();

        var css = theme == AppTheme.Dark
            ? GetDarkThemeCss()
            : GetLightThemeCss();

        _cssProvider.LoadFromData(css);

        Gtk.StyleContext.AddProviderForScreen(
            Gdk.Screen.Default,
            _cssProvider,
            Gtk.STYLE_PROVIDER_PRIORITY_APPLICATION
        );
    }

    private string GetDarkThemeCss()
    {
        return @"
            * {
                background-color: #2b2b2b;
                color: #ffffff;
            }
            button {
                background-color: #3c3c3c;
                border: 1px solid #555555;
            }
            button:hover {
                background-color: #4c4c4c;
            }
        ";
    }
}
```

This comprehensive theme detection and integration system ensures that MAUI applications on Linux feel native and respect user preferences across all major desktop environments.

While OpenMaui provides comprehensive platform services out of the box, there are scenarios where you might need to implement custom services or extend existing ones. This section provides practical guidance for creating your own platform services.

## Creating a Custom Service Interface

First, define a cross-platform interface in your shared MAUI project:

```csharp
public interface ICustomPlatformService
{
    Task<string> GetSystemInformationAsync();
    Task<bool> PerformPlatformSpecificOperationAsync(string parameter);
    event EventHandler<PlatformEventArgs> PlatformEventOccurred;
}

public class PlatformEventArgs : EventArgs
{
    public string EventType { get; set; }
    public object Data { get; set; }
}
```

## Implementing the Linux-Specific Service

Create a Linux-specific implementation in your platform project:

```csharp
public class LinuxCustomPlatformService : ICustomPlatformService
{
    private readonly ILogger<LinuxCustomPlatformService> _logger;
    private DBusConnection _dbusConnection;

    public event EventHandler<PlatformEventArgs> PlatformEventOccurred;

    public LinuxCustomPlatformService(ILogger<LinuxCustomPlatformService> logger)
    {
        _logger = logger;
        InitializeDBusMonitoring();
    }

    public async Task<string> GetSystemInformationAsync()
    {
        try
        {
            // Query system information via D-Bus
            var connection = await DBusConnection.ConnectSystemBusAsync();

            var result = await connection.CallMethodAsync(
                "org.freedesktop.hostname1",
                "/org/freedesktop/hostname1",
                "org.freedesktop.DBus.Properties",
                "GetAll",
                new object[] { "org.freedesktop.hostname1" }
            );

            return ProcessSystemInfo(result);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to get system information");
            return "Unknown";
        }
    }

    public async Task<bool> PerformPlatformSpecificOperationAsync(string parameter)
    {
        // Example: Execute a command-line operation
        var process = new Process
        {
            StartInfo = new ProcessStartInfo
            {
                FileName = "/bin/bash",
                Arguments = $"-c \"{parameter}\"",
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                UseShellExecute = false
            }
        };

        process.Start();
        await process.WaitForExitAsync();

        return process.ExitCode == 0;
    }

    private void InitializeDBusMonitoring()
    {
        Task.Run(async () =>
        {
            _dbusConnection = await DBusConnection.ConnectSessionBusAsync();

            await _dbusConnection.AddMatchAsync(
                "type='signal',interface='org.custom.Interface'"
            );

            _dbusConnection.OnSignal += (sender, args) =>
            {
                PlatformEventOccurred?.Invoke(this, new PlatformEventArgs
                {
                    EventType = args.Member,
                    Data = args.Parameters
                });
            };
        });
    }
}
```

## Registering the Custom Service

Register your service during application configuration:

```csharp
public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureLinuxPlatform();

#if LINUX
        // Register custom Linux service
        builder.Services.AddSingleton<ICustomPlatformService, LinuxCustomPlatformService>();
#elif WINDOWS
        builder.Services.AddSingleton<ICustomPlatformService, WindowsCustomPlatformService>();
#elif ANDROID || IOS
        builder.Services.AddSingleton<ICustomPlatformService, MobileCustomPlatformService>();
#endif

        return builder.Build();
    }
}
```

